import{_ as s,C as o,o as t,c as n,a2 as i,b as d,w as a,a as l,E as c,a3 as u}from"./chunks/framework.Crpw6aS5.js";const A=JSON.parse('{"title":"Sécurité","description":"","frontmatter":{},"headers":[],"relativePath":"fr/technical/security.md","filePath":"fr/technical/security.md"}'),h={name:"fr/technical/security.md"};function p(m,e,b,g,f,q){const r=o("Mermaid");return t(),n("div",null,[e[1]||(e[1]=i('<h1 id="securite" tabindex="-1">Sécurité <a class="header-anchor" href="#securite" aria-label="Permalink to &quot;Sécurité&quot;">​</a></h1><p>Vue d&#39;ensemble des mesures de sécurité implémentées dans Nid.</p><hr><h2 id="authentification" tabindex="-1">Authentification <a class="header-anchor" href="#authentification" aria-label="Permalink to &quot;Authentification&quot;">​</a></h2><h3 id="jwt-httponly" tabindex="-1">JWT httpOnly <a class="header-anchor" href="#jwt-httponly" aria-label="Permalink to &quot;JWT httpOnly&quot;">​</a></h3><p>Les tokens JWT sont stockés dans des <strong>cookies httpOnly</strong>, inaccessibles au JavaScript côté client. Cela protège contre les attaques XSS qui tenteraient de voler les tokens.</p><ul><li><strong>Access token</strong> : durée courte (15 min par défaut), utilisé pour chaque requête API</li><li><strong>Refresh token</strong> : durée longue (30 jours par défaut), utilisé uniquement pour renouveler l&#39;access token</li></ul><h3 id="blacklist-jwt-redis" tabindex="-1">Blacklist JWT Redis <a class="header-anchor" href="#blacklist-jwt-redis" aria-label="Permalink to &quot;Blacklist JWT Redis&quot;">​</a></h3><p>Au logout, le token est ajouté à une blacklist Redis. Le middleware <code>authenticate</code> vérifie cette blacklist à chaque requête, permettant l&#39;<strong>invalidation immédiate</strong> d&#39;un token compromis.</p><h3 id="hashage-des-mots-de-passe" tabindex="-1">Hashage des mots de passe <a class="header-anchor" href="#hashage-des-mots-de-passe" aria-label="Permalink to &quot;Hashage des mots de passe&quot;">​</a></h3><p>Les mots de passe sont hashés avec <strong>bcrypt</strong> (12 rounds). Un hash factice est calculé même quand l&#39;utilisateur n&#39;existe pas, ce qui empêche l&#39;énumération de comptes par timing attack.</p><h3 id="rate-limiting" tabindex="-1">Rate limiting <a class="header-anchor" href="#rate-limiting" aria-label="Permalink to &quot;Rate limiting&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Route</th><th>Limite</th></tr></thead><tbody><tr><td><code>POST /api/auth/register</code></td><td>3 requêtes / minute</td></tr><tr><td><code>POST /api/auth/login</code></td><td>5 requêtes / minute</td></tr><tr><td>Routes générales</td><td>100 requêtes / minute / IP</td></tr></tbody></table><h3 id="_2fa-totp" tabindex="-1">2FA TOTP <a class="header-anchor" href="#_2fa-totp" aria-label="Permalink to &quot;2FA TOTP&quot;">​</a></h3><p>L&#39;authentification à deux facteurs est optionnelle pour les comptes locaux. Elle utilise <strong>TOTP</strong> (RFC 6238) via <code>otplib</code>, avec génération de QR code pour la configuration.</p><h3 id="sso-multi-providers" tabindex="-1">SSO multi-providers <a class="header-anchor" href="#sso-multi-providers" aria-label="Permalink to &quot;SSO multi-providers&quot;">​</a></h3><p>Le Social Login utilise la librairie <strong>Arctic</strong> avec échange de code OAuth2 côté serveur. Les tokens sociaux ne transitent jamais par le frontend.</p><p>Providers supportés : Google, Microsoft, Discord, Facebook, LinkedIn, Keycloak.</p><hr><h2 id="autorisation" tabindex="-1">Autorisation <a class="header-anchor" href="#autorisation" aria-label="Permalink to &quot;Autorisation&quot;">​</a></h2><h3 id="isolation-multi-utilisateurs" tabindex="-1">Isolation multi-utilisateurs <a class="header-anchor" href="#isolation-multi-utilisateurs" aria-label="Permalink to &quot;Isolation multi-utilisateurs&quot;">​</a></h3><p>Deux décorateurs Fastify assurent l&#39;isolation des données :</p><ul><li><strong><code>requireAccountOwnership</code></strong> — Vérifie que le paramètre <code>:accountId</code> appartient à l&#39;utilisateur authentifié. Appliqué sur toutes les routes Gmail, archive, dashboard et règles.</li><li><strong><code>requireAdmin</code></strong> — Vérifie que <code>role === &#39;admin&#39;</code> dans le JWT. Appliqué sur les routes admin et intégrité.</li></ul>',23)),(t(),d(u,null,{default:a(()=>[c(r,{id:"mermaid-118",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20REQ%5BRequ%C3%AAte%20HTTP%5D%20--%3E%20AUTH%5Bauthenticate%5D%0A%20%20%20%20AUTH%20--%3E%20OWN%7BrequireAccountOwnership%7D%0A%20%20%20%20OWN%20--%3E%7COK%7C%20HANDLER%5BHandler%20route%5D%0A%20%20%20%20OWN%20--%3E%7C403%7C%20REJECT%5BAcc%C3%A8s%20refus%C3%A9%5D%0A%20%20%20%20%0A%20%20%20%20AUTH%20--%3E%20ADM%7BrequireAdmin%7D%0A%20%20%20%20ADM%20--%3E%7COK%7C%20ADMIN_HANDLER%5BHandler%20admin%5D%0A%20%20%20%20ADM%20--%3E%7C403%7C%20REJECT%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=i('<h3 id="roles" tabindex="-1">Rôles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Rôles&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rôle</th><th>Accès</th></tr></thead><tbody><tr><td><code>user</code></td><td>Ses propres données (mails, archives, règles, jobs, notifications)</td></tr><tr><td><code>admin</code></td><td>Idem + page administration (utilisateurs, jobs globaux, quotas, intégrité)</td></tr></tbody></table><hr><h2 id="validation-des-entrees" tabindex="-1">Validation des entrées <a class="header-anchor" href="#validation-des-entrees" aria-label="Permalink to &quot;Validation des entrées&quot;">​</a></h2><p>Toutes les entrées utilisateur sont validées avec <strong>Zod</strong> :</p><ul><li>Schémas stricts sur les corps de requête, query params et paramètres d&#39;URL</li><li>Types TypeScript inférés depuis les schémas Zod</li><li>Rejet automatique des champs inconnus</li></ul><p>La recherche full-text utilise <code>plainto_tsquery</code> (et non <code>to_tsquery</code>), ce qui neutralise les opérateurs de requête et protège contre l&#39;injection d&#39;opérateurs PostgreSQL.</p><hr><h2 id="chiffrement-des-archives" tabindex="-1">Chiffrement des archives <a class="header-anchor" href="#chiffrement-des-archives" aria-label="Permalink to &quot;Chiffrement des archives&quot;">​</a></h2><p>Les archives EML peuvent être chiffrées au repos sur le NAS :</p><table tabindex="0"><thead><tr><th>Paramètre</th><th>Valeur</th></tr></thead><tbody><tr><td>Algorithme</td><td>AES-256-GCM (confidentialité + intégrité)</td></tr><tr><td>Dérivation de clé</td><td>PBKDF2 (SHA-512, 100 000 itérations)</td></tr><tr><td>Salt</td><td>32 octets aléatoires par fichier</td></tr><tr><td>IV</td><td>12 octets aléatoires par fichier</td></tr><tr><td>Stockage passphrase</td><td>Hash scrypt en base — jamais la passphrase elle-même</td></tr></tbody></table><h3 id="format-binaire" tabindex="-1">Format binaire <a class="header-anchor" href="#format-binaire" aria-label="Permalink to &quot;Format binaire&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GMENC01 (7 B) | SALT (32 B) | IV (12 B) | AUTH_TAG (16 B) | CIPHERTEXT</span></span></code></pre></div><ul><li>Magic bytes <code>GMENC01</code> pour la détection des fichiers chiffrés</li><li>Déchiffrement à la volée sans fichier temporaire</li><li>Idempotence : les fichiers déjà chiffrés sont ignorés</li></ul><hr><h2 id="securite-reseau" tabindex="-1">Sécurité réseau <a class="header-anchor" href="#securite-reseau" aria-label="Permalink to &quot;Sécurité réseau&quot;">​</a></h2><h3 id="production" tabindex="-1">Production <a class="header-anchor" href="#production" aria-label="Permalink to &quot;Production&quot;">​</a></h3><ul><li>PostgreSQL et Redis ne sont <strong>pas exposés</strong> sur l&#39;hôte</li><li>Seul le port 3000 (Nginx) est accessible</li><li>CORS configuré sur <code>FRONTEND_URL</code> uniquement</li></ul><h3 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h3><p>Les webhooks de type <code>generic</code> incluent un header <code>X-Webhook-Signature</code> contenant un HMAC-SHA256 du payload, permettant au destinataire de vérifier l&#39;authenticité de la requête.</p><hr><h2 id="securite-des-fichiers" tabindex="-1">Sécurité des fichiers <a class="header-anchor" href="#securite-des-fichiers" aria-label="Permalink to &quot;Sécurité des fichiers&quot;">​</a></h2><ul><li>Les noms de fichiers dans les headers <code>Content-Disposition</code> sont sanitisés</li><li>Les chemins de fichiers sont validés pour empêcher les traversées de répertoire</li><li>Les fichiers EML sont identifiés par UUID, pas par des chemins utilisateur</li></ul><hr><h2 id="audit" tabindex="-1">Audit <a class="header-anchor" href="#audit" aria-label="Permalink to &quot;Audit&quot;">​</a></h2><p>Toutes les actions sensibles sont tracées dans le journal d&#39;audit :</p><table tabindex="0"><thead><tr><th>Catégorie</th><th>Actions tracées</th></tr></thead><tbody><tr><td>Authentification</td><td>Connexion, déconnexion, inscription, échec de login</td></tr><tr><td>Comptes Gmail</td><td>Connexion, déconnexion d&#39;un compte</td></tr><tr><td>Règles</td><td>Création, modification, suppression, exécution</td></tr><tr><td>Opérations bulk</td><td>Suppression, archivage, modification de labels</td></tr><tr><td>Configuration</td><td>Export, import</td></tr><tr><td>Administration</td><td>Modification d&#39;utilisateur, changement de rôle</td></tr></tbody></table><p>Chaque entrée inclut l&#39;adresse IP de la requête pour la traçabilité.</p><hr><h2 id="securite-des-conteneurs-docker" tabindex="-1">Sécurité des conteneurs Docker <a class="header-anchor" href="#securite-des-conteneurs-docker" aria-label="Permalink to &quot;Sécurité des conteneurs Docker&quot;">​</a></h2><h3 id="images-de-base" tabindex="-1">Images de base <a class="header-anchor" href="#images-de-base" aria-label="Permalink to &quot;Images de base&quot;">​</a></h3><ul><li><strong>Images Alpine</strong> — Utilisation systématique de variantes Alpine pour réduire la surface d&#39;attaque (moins de binaires, moins de CVE potentielles)</li><li><strong>Mises à jour</strong> — <code>apk upgrade --no-cache</code> en production pour appliquer les correctifs de sécurité</li></ul><h3 id="build-multi-stage" tabindex="-1">Build multi-stage <a class="header-anchor" href="#build-multi-stage" aria-label="Permalink to &quot;Build multi-stage&quot;">​</a></h3><p>Les Dockerfiles utilisent un <strong>build multi-stage</strong> (builder → deps → runner) pour que l&#39;image finale ne contienne :</p><ul><li>Ni le code source</li><li>Ni les devDependencies</li><li>Ni les outils de build (npm, corepack, yarn)</li></ul><h3 id="utilisateur-non-root" tabindex="-1">Utilisateur non-root <a class="header-anchor" href="#utilisateur-non-root" aria-label="Permalink to &quot;Utilisateur non-root&quot;">​</a></h3><p>Toutes les images de production tournent avec un <strong>utilisateur non-root</strong> (<code>appuser:appgroup</code>, UID/GID 1001). Cela limite l&#39;impact d&#39;une éventuelle compromission du processus Node.js.</p><h3 id="dockerignore" tabindex="-1"><code>.dockerignore</code> <a class="header-anchor" href="#dockerignore" aria-label="Permalink to &quot;`.dockerignore`&quot;">​</a></h3><p>Des fichiers <code>.dockerignore</code> empêchent la copie de fichiers sensibles dans le contexte de build :</p><ul><li><code>.env</code>, <code>.env.*</code>, <code>*.pem</code>, <code>*.key</code> — Variables d&#39;environnement et secrets</li><li><code>.git</code> — Historique Git</li><li><code>node_modules</code>, <code>coverage</code>, <code>dist</code> — Artefacts de build</li><li><code>volumes/</code> — Données utilisateur</li></ul><h3 id="reseau-interne" tabindex="-1">Réseau interne <a class="header-anchor" href="#reseau-interne" aria-label="Permalink to &quot;Réseau interne&quot;">​</a></h3><p>En production, PostgreSQL et Redis ne sont <strong>pas exposés</strong> sur l&#39;hôte — ils communiquent uniquement via le réseau Docker interne. Seul le port 3000 (Nginx) est accessible.</p><h3 id="ignore-scripts" tabindex="-1"><code>--ignore-scripts</code> <a class="header-anchor" href="#ignore-scripts" aria-label="Permalink to &quot;`--ignore-scripts`&quot;">​</a></h3><p>Les commandes <code>npm ci</code> de production utilisent <code>--ignore-scripts</code> pour empêcher l&#39;exécution de scripts <code>postinstall</code> potentiellement malveillants dans les dépendances.</p>',44))])}const x=s(h,[["render",p]]);export{A as __pageData,x as default};
